protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(b =>
    {
        b.ToContainer("Products");

        // EF Core 9 renamed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
        b.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer embeds the discriminator in the JSON id.
        // Existing documents have ids like "Product|123"; without this flag,
        // FindAsync would look for "123" and miss every existing document.
        b.HasRootDiscriminatorInJsonId(true);
    });

    // REMOVED: HasIndex() now throws at startup for Cosmos DB entities.
    // Manage indexing via the container's indexing policy (Azure Portal / Bicep / Terraform).
}

