using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator still works because we configured
        // HasDiscriminator<string>("Discriminator") to keep the old property name.
        // Without that, EF Core 9 would write "$type" and this query would find nothing.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider no longer supports synchronous I/O (ToList, SaveChanges, etc.).
        // All queries must use async equivalents.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

